const globalKeys = global.keys();

globalKeys.forEach(key => {
    global.set(key,'')
});


return msg;

//  for disable product button and change user note


if(global.get('state')=="open" || global.get('state')==undefined || global.get('state')==""){
    msg.enabled = false;
    msg.payload="You can start production after setup is completed, click setup again to finish setup"
    global.set('state', "close")
    return msg;
}else{
    msg.enabled = true;
    global.set('state', "open")
    msg.payload=""
    return msg;  
}

global.set('productInfo',msg.payload)
const months = [
    "Jan", "Feb", "Mar", "Apr", "May", "Jun",
    "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
  ];

  const currentDate = new Date();
  const day = currentDate.getDate();
  const month = months[currentDate.getMonth()];
  const year = currentDate.getFullYear();
  const hours = currentDate.getHours();
  const minutes = currentDate.getMinutes();

  // Add leading zeros if needed
  const formattedDay = day < 10 ? `0${day}` : day;
  const formattedHours = hours < 10 ? `0${hours}` : hours;
  const formattedMinutes = minutes < 10 ? `0${minutes}` : minutes;

  msg.payload.currentTime =  `${formattedDay} ${month} ${year} ${formattedHours}:${formattedMinutes}`;

return msg;

global.set('currentInteruption',msg.payload);
msg.payload = { "pages": { "show": ["Terminal"] }, "groups": { "show": ["Interuption page"], "hide": ["Production button row 1", "Production button row 2", "Production text row","Production footer"] } }
return msg;

 const { days, hours, minutes, seconds, milliseconds } = msg.elapsed.time
  msg.payload =  `${days}:${hours}:${minutes}:${seconds}:${milliseconds}`;
let currentInteruption = global.get('currentInteruption')

if(currentInteruption=='break'){
  global.set("breakTime", msg.payload)
} else if (currentInteruption=='changeover'){
  global.set("changeOverTime", msg.payload)
} else if (currentInteruption=='machine error'){
  global.set("machineErrorTime", msg.payload)
} else if (currentInteruption =='raw material shortage'){
  global.set("rawMaterialStorageTime", msg.payload)
}else if(currentInteruption == 'maintenance'){
  global.set("maintenanceTime", msg.payload)
}

return msg;

function updateCollection(collectionName, valuePropertyName) {
  const collection = global.get(collectionName) || [];
  const value = global.get(valuePropertyName);
  collection.push(value);
  global.set(collectionName, collection);
}

let currentInteruption = global.get('currentInteruption');

if (currentInteruption) {
  if (currentInteruption === 'break') {
    updateCollection("break-time-collection", "breakTime");
  } else if (currentInteruption === 'changeover') {
    updateCollection("change-over-time-collection", "changeOverTime");
  } else if (currentInteruption === 'machine error') {
    updateCollection("machine-error-time-collection", "machineErrorTime");
  } else if (currentInteruption === 'maintenance') {
    updateCollection("maintenance-time-collection", "maintenanceTime");
  } else if (currentInteruption === 'raw material shortage') {
    updateCollection("raw-material-time-collection", "rawMaterialStorageTime");
  }
}

return msg;

let tableData = global.get('data', 'persistent') || [];
let productId = global.get("productInfo")['product-id'];
let productTime = global.get("productInfo")['currentTime'];

// Get the last entry from each interruption array
let interruptionArrays = [
    "break-time-collection",
    "change-over-time-collection",
    "machine-error-time-collection",
    "raw-material-time-collection",
    "maintenance-time-collection"
];

let interruptions = interruptionArrays.map(interruptionArray => {
    let currentArray = global.get(interruptionArray);
    return (Array.isArray(currentArray) && currentArray.length > 0) ? currentArray.slice(-1)[0] : "-";
});

// Get the number of defect and good parts
let defectParts = global.get("defect-parts") || {};
let badParts = defectParts['bad-part'] !== undefined ? defectParts['bad-part'] : "-";
let goodParts = defectParts['good-part'] !== undefined ? defectParts['good-part'] : "-";

// Construct the payload
let payload = {
    "Product Id": `${productId}`,
    "Production Started": `${productTime}`,
    "Break Interruption": interruptions[0],
    "Change-Over Interruption": interruptions[1],
    "Machine Error Interruption": interruptions[2],
    "Raw Material Storage Interruption": interruptions[3],
    "Maintenance Interruption": interruptions[4],
    "Defect Parts": badParts,
    "Good Parts": goodParts
};

tableData.push(payload);
global.set('data', tableData, 'persistent');

msg.payload = tableData
return msg;

